services.description:
### 接口地址1
POST http://127.0.0.1:5000/api/ocr

### 请求参数
- file : 图片文件 (支持 png, jpg, jpeg, bmp, tiff, webp 格式)
- 文件大小限制: 16MB

### 接口地址2
POST http://127.0.0.1:5000/api/ocr/base64
### 请求参数
{
  "image": "base64编码的图片数据"
}

### 返回格式

{
  "success": true,
  "data": {
    "filename": "20231201_123456_abcdef.jpg",
    "text_count": 5,
    "elapsed_time": 0.85,
    "texts": [
      {
        "text": "识别的文字内容",
        "confidence": 0.99,
        "bbox": [[x1, y1], [x2, y2], [x3, y3], [x4, y4]]
      }
    ]
  }
}
